"use strict";dotclear.ready(()=>{dotclear.wordcount=dotclear.getData("wordcount");dotclear.wordcount.timer=setInterval(()=>{dotclear.jsonServicesPost("wordCountGetCounters",t=>{if(t.ret){const e=document.querySelector("div.wordcount details p");e&&(e.innerHTML=t.html)}},{excerpt:document.getElementById("post_excerpt")?.value,content:document.getElementById("post_content")?.value,format:document.getElementById("post_format")?.value})},1e3*(dotclear.wordcount?.interval||60))});
